#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        n = int(next(it)); x = int(next(it))
        flavours = set()
        for _ in range(n):
            flavours.add(int(next(it)))
        distinct = len(flavours)
        eat_limit = n - x
        ans = distinct if distinct < eat_limit else eat_limit
        if ans < 0:
            ans = 0
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

